import React, { useCallback, useEffect, useRef } from 'react'
import { useCountdownStore } from './useCountDownStore'

function useCountdown() {
    const { initialSeconds, setIsRunning, setTimeLeft, timeLeft } = useCountdownStore((state) => state)
    const intervalRef = useRef(null)

    const start = (timeLeft) => {
        setIsRunning(true)
        if (timeLeft <= 0) {
            clearInterval(intervalRef)
            intervalRef.current = null
            setIsRunning(false)
            setTimeLeft(0)
        } else {
            console.log('timeLeft???', timeLeft)
            setTimeLeft(timeLeft - 1)
            intervalRef.current = setTimeout((timeLeft) => {
                start(timeLeft)
            }, 1000, timeLeft)

        }
    }

    const pause = useCallback(() => {
        clearInterval(intervalRef)
        intervalRef.current = null
        setIsRunning(false)
    }, [])

    const reset = useCallback(() => {
        clearInterval(intervalRef)
        intervalRef.current = null
        setIsRunning(false)
        setTimeLeft(initialSeconds)
    }, [initialSeconds])

    return { start, pause, reset }
}

export default useCountdown
